      |> Repo.all()

    json(conn, %{products: products, count: length(products)})
  end

  defp build_search_query(query, "") do
    query
  end

  defp build_search_query(query, search_term) do
    from(p in query,
      where: fragment("name LIKE ?", ^"%#{search_term}%") or
             fragment("description LIKE ?", ^"%#{search_term}%") or
             fragment("sku LIKE ?", ^"%#{search_term}%")
    )
  end

  defp build_price_query(query, nil, nil), do: query

  defp build_price_query(query, min_price, nil) when not is_nil(min_price) do
    from(p in query, where: p.price >= ^min_price)
  end

  defp build_price_query(query, nil, max_price) when not is_nil(max_price) do
    from(p in query, where: p.price <= ^max_price)
  end

  defp build_price_query(query, min_price, max_price) do
    from(p in query, where: p.price >= ^min_price and p.price <= ^max_price)
  end

  defp build_category_query(query, nil), do: query

  defp build_category_query(query, category) do
    from(p in query, where: fragment("category = ?", ^category))
