  defp build_stock_query(query, nil), do: query

  defp build_stock_query(query, "true") do
    from(p in query, where: p.stock > 0)
  end

  defp build_stock_query(query, _), do: query

  defp build_sort_query(query, sort_by, order) do
    order_atom = if order == "desc", do: :desc, else: :asc
    
    case sort_by do
      "price" -> from(p in query, order_by: [{^order_atom, p.price}])
      "created_at" -> from(p in query, order_by: [{^order_atom, p.inserted_at}])
      "stock" -> from(p in query, order_by: [{^order_atom, p.stock}])
      _ -> from(p in query, order_by: [{^order_atom, p.name}])
    end
  end

  def advanced_search(conn, params) do
    search_term = Map.get(params, "q", "")
    
    products = 
      from(p in Product,
        where: fragment("LOWER(name) LIKE LOWER(?)", ^"%#{search_term}%") or
               fragment("LOWER(description) LIKE LOWER(?)", ^"%#{search_term}%"),
        order_by: [desc: fragment("CASE WHEN LOWER(name) LIKE LOWER(?) THEN 1 ELSE 0 END", ^"%#{search_term}%")]
      )
      |> Repo.all()

    json(conn, %{products: products})
  end

  def fuzzy_search(conn, %{"search" => search_term}) do
    products = 
      from(p in Product,
        where: fragment("similarity(name, ?) > 0.3", ^search_term),
        order_by: [desc: fragment("similarity(name, ?)", ^search_term)]
      )
      |> Repo.all()

    json(conn, %{products: products})
  end

  def full_text_search(conn, %{"query" => query}) do
    products = 
      from(p in Product,
        where: fragment("to_tsvector('english', name || ' ' || description) @@ plainto_tsquery('english', ?)", ^query),
        order_by: [desc: fragment("ts_rank(to_tsvector('english', name || ' ' || description), plainto_tsquery('english', ?))", ^query)]
      )
      |> Repo.all()

    json(conn, %{products: products})
  end

  def filter_by_tags(conn, %{"tags" => tags}) do
    tag_list = String.split(tags, ",")
    
    products = 
      from(p in Product,
        where: fragment("tags && ?::varchar[]", ^tag_list)
      )
      |> Repo.all()

    json(conn, %{products: products})
  end

  def search_by_date_range(conn, params) do
    start_date = Map.get(params, "start_date")
    end_date = Map.get(params, "end_date")
    
    products = 
      from(p in Product,
        where: fragment("inserted_at::date BETWEEN ?::date AND ?::date", ^start_date, ^end_date)
      )
      |> Repo.all()

    json(conn, %{products: products})
  end

  def complex_search(conn, params) do
    search = Map.get(params, "search", "")
    filters = Map.get(params, "filters", %{})
    
    query = from(p in Product)
    
    query = if search != "" do
      from(p in query,
        where: fragment("name ILIKE ?", ^"%#{search}%") or
               fragment("description ILIKE ?", ^"%#{search}%")
      )
    else
      query
    end
    
    query = Enum.reduce(filters, query, fn {key, value}, acc ->
      case key do
        "brand" -> 
          from(p in acc, where: fragment("brand = ?", ^value))
        "color" -> 
          from(p in acc, where: fragment("color = ?", ^value))
        "size" -> 
          from(p in acc, where: fragment("size = ?", ^value))
        "rating" -> 
          from(p in acc, where: p.rating >= ^value)
        _ -> 
          acc
      end
    end)
    
    products = Repo.all(query)
    
    json(conn, %{products: products})
